"""matplotlib.backend_tools — tool base classes."""

class ToolBase:
    default_keymap = None
    description = ''
    image = None
    def __init__(self, toolmanager, name): self.name = name
    def trigger(self, sender, event, data=None): pass
    def set_figure(self, figure): pass

class ToolToggleBase(ToolBase):
    radio_group = None
    cursor = None
    def enable(self, event=None): pass
    def disable(self, event=None): pass

class ToolSetCursor(ToolBase): pass
class ToolCursorPosition(ToolBase): pass
class ToolViewsPositions(ToolBase): pass
class ToolHome(ToolBase): pass
class ToolBack(ToolBase): pass
class ToolForward(ToolBase): pass
class SaveFigureBase(ToolBase): pass
class ZoomPanBase(ToolToggleBase): pass
class ToolZoom(ZoomPanBase): pass
class ToolPan(ZoomPanBase): pass
class ToolFullScreen(ToolToggleBase): pass
class ToolGrid(ToolBase): pass
class ToolMinorGrid(ToolBase): pass
class ToolCopyToClipboardBase(ToolBase): pass
class ToolHelpBase(ToolBase): pass
class ToolQuitAll(ToolBase): pass
class ToolQuit(ToolBase): pass
class ToolXScale(ToolBase): pass
class ToolYScale(ToolBase): pass

default_tools = {}
default_toolbar_tools = []
